var express = require('express')
  , app = express()
  , parser = require('xml2js').Parser({trim: true}); // add trim flag to avoid warning messages in parser
app.post('/upload', function (req, res) {

  var file = req.files;

  if(file != null && file instanceof Array){
    file.forEach(function (fileItem) {
      // fileItem = {
      //     name: 'sample.xml',
      //     path: '/tmp/54728-20190331T060826.847Z',
      //     size: 399,
      //     encoding: '7bit',
      //     mimetype: 'application/xml' }
      parser.parseString(fileItem.path, function (err, result) {
        var output = [];

        // remove the xml declaration
        delete result.$['__cdata'];
        
        for (var i in result){
          output[i] = {};

          if(typeof result[i].$ === 'object'){
            Object.assign(output[i], result[i]);
          } else if(result[i] instanceof Array) {
            
            let key = 0;

            result[i].forEach((item)=>{
              item.$['@']['key'] = i + '_' + (++key);

              output[i][item.$['@'].key] = {};

              Object.assign(output[i][item.$['@'].key], item.$)
            })
          }
        }

        res.end('data:text/json;charset=UTF-8,'+ JSON.stringify(output));
      });
    });
  };
});
app.listen(3001, function () {console.log('Example app listening on port 3000!')})

